function MakePage($c, $all) {
  $toolCards = ($c.Tools | ForEach-Object {
    "<a class=`"tool-card`" href=`"$($_[1])`"><div class=`"tool-top`"><span class=`"tool-icon`"><i class=`"$($_[3])`"></i></span><span class=`"tool-tag`">$($c.Title)</span></div><h3>$($_[0])</h3><p>$($_[2])</p><span class=`"tool-link`">Open tool <i class=`"fa-solid fa-arrow-right`"></i></span></a>"
  }) -join "`n"
  $related = ($all | Where-Object { $_.File -ne $c.File } | Select-Object -First 4 | ForEach-Object { "<a href=`"$($_.File)`">$($_.Title)</a>" }) -join "`n                    "
  @"
