ize:.9rem;font-weight:800}h1,h2,h3{margin-top:0;line-height:1.1}.hero-copy h1{margin-bottom:16px;font-size:clamp(2.4rem,5vw,4rem);letter-spacing:-.04em}.hero-copy p,.section-card p,.section-card li{color:var(--muted)}.hero-stats{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:14px;margin-top:22px}.hero-stat{padding:18px;border-radius:18px;background:rgba(255,255,255,0.8);border:1px solid var(--border)}.hero-stat strong{display:block;margin-bottom:4px;font-size:1.35rem}.hero-aside{display:grid;gap:16px;align-content:start}.aside-card{padding:22px;border-radius:24px;background:linear-gradient(180deg,rgba(13,37,61,0.95),rgba(18,51,81,0.92));color:#fff}.aside-card p{color:rgba(255,255,255,0.76)}.section-card{margin-top:24px;padding:28px;border-radius:28px;background:var(--surface);border:1px solid rgba(255,255,255,0.7);box-shadow:var(--shadow)}.tools-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:16px}.tool-card{padding:22px;border-radius:22px;background:linear-gradient(180deg,#ffffff,#f7fbff);border:1px solid var(--border)}.tool-top{display:flex;justify-content:space-between;align-items:start;gap:12px;margin-bottom:16px}.tool-icon{width:50px;height:50px;display:grid;place-items:center;border-radius:16px;color:#fff;background:linear-gradient(135deg,var(--primary),var(--accent));font-size:1.1rem}.tool-tag{padding:7px 10px;border-radius:999px;background:rgba(34,125,255,0.08);color:var(--primary-deep);font-size:.76rem;font-weight:800;text-transform:uppercase;letter-spacing:.04em}.tool-link{display:inline-flex;align-items:center;gap:8px;color:var(--primary-deep);font-weight:800}.seo-box ul{margin:0;padding-left:18px}.related-links{display:flex;flex-wrap:wrap;gap:10px}.related-links a{padding:11px 14px;border-radius:999px;background:#fff;border:1px solid var(--border);color:var(--muted);font-weight:700}footer{padding:18px 0 34px}.footer-panel{display:flex;justify-content:space-between;align-items:center;gap:18px;flex-wrap:wrap;padding:24px