foreach ($c in $cats) { MakePage $c $cats | Set-Content -Path (Join-Path $root $c.File) -Encoding UTF8 }

$indexPath = Join-Path $root 'index.html'
$index = Get-Content -Path $indexPath -Raw
$index = $index.Replace('link: "calculators/agecalculator.html"', 'link: "calculators.html"').Replace('link: "developerTools/json-formatter.html"', 'link: "developer-tools.html"').Replace('link: "generators/qr.html"', 'link: "generators.html"').Replace('link: "imagetools/image-compressor.html"', 'link: "image-tools.html"').Replace('link: "pdfTools/merge-pdf.html"', 'link: "pdf-tools.html"').Replace('link: "SecurityTools/password.html"', 'link: "security-tools.html"').Replace('link: "SEOTools/metataggenerator.html"', 'link: "seo-tools.html"').Replace('link: "textTools/wordcounter.html"', 'link: "text-tools.html"')
