$files = Get-ChildItem -Path $root -Recurse -Filter *.html | Where-Object { $_.FullName -ne (Join-Path $root 'qr.html') }
$base = 'https://supertools1.site'
$catPages = @('calculators.html','developer-tools.html','generators.html','image-tools.html','pdf-tools.html','security-tools.html','seo-tools.html','text-tools.html')
$entries = foreach ($f in $files) {
  $rel = $f.FullName.Substring($root.Length).TrimStart('\').Replace('\','/')
  $loc = if ($rel -ieq 'index.html') { "$base/" } else { "$base/$rel" }
  $priority = if ($rel -ieq 'index.html') { '1.0' } elseif ($rel -in @('about.html','contact.html','privacy.html')) { '0.8' } elseif ($rel -in $catPages) { '0.95' } else { '0.9' }
  [PSCustomObject]@{Relative=$rel;Loc=$loc;LastMod=$f.LastWriteTime.ToString('yyyy-MM-dd');Priority=$priority}
}
function Rank($r){ if($r -ieq 'index.html'){0}elseif($r -in @('about.html','contact.html','privacy.html')){1}elseif($r -in $catPages){2}elseif($r -match '^calculators/'){3}elseif($r -match '^developerTools/'){4}elseif($r -match '^generators/'){5}elseif($r -match '^imagetools/'){6}elseif($r -match '^pdfTools/'){7}elseif($r -match '^SecurityTools/'){8}elseif($r -match '^SEOTools/'){9}elseif($r -match '^textTools/'){10}else{11}}
$entries = $entries | Sort-Object @{Expression={Rank $_.Relative}}, Relative
$xml = New-Object System.Text.StringBuilder
[void]$xml.AppendLine('<?xml version="1.0" encoding="UTF-8"?>')
[void]$xml.AppendLine('<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">')
[void]$xml.AppendLine('')
foreach($e in $entries){[void]$xml.AppendLine('  <url>');[void]$xml.AppendLine("    <loc>$($e.Loc)</loc>");[void]$xml.AppendLine("    <lastmod>$($e.LastMod)</lastmod>");[void]$xml.AppendLine("    <priority>$($e.Priority)</priority>");[void]$xml.AppendLine('  </url>');[void]$xml.AppendLine('')}
[void]$xml.AppendLine('</urlset>')
Set-Content -Path (Join-Path $root 'sitemap.xml') -Value $xml.ToString() -Encoding UTF8
Write-Output "Created $($cats.Count) category pages and updated sitemap with $($entries.Count) URLs."
